INSERT INTO `pc_windows_services` VALUES
(2120,2,'ADPSvc','Service de plateforme de données agrégées','Ce service est utilisé pour les scénarios de plateforme de données agrégées.','Stopped','Manual'),
(2121,2,'ALG','Service de la passerelle de la couche Application','Fournit la prise en charge de plug-ins de protocole tiers pour le partage de connexion Internet','Stopped','Manual'),
(2122,2,'AppIDSvc','Identité de l’application','Détermine et vérifie l’identité d’une application. La désactivation de ce service empêchera l’application d’AppLocker.','Running','Manual'),
(2123,2,'Appinfo','Informations d’application','Permet d’exécuter les applications interactives avec des droits d’administration supplémentaires. Si ce service est arrêté, les utilisateurs ne pourront pas lancer les applications avec les droits d’administration supplémentaires nécessaires pour effectuer les tâches utilisateur souhaitées.','Running','Manual'),
(2124,2,'AppMgmt','Gestion d’applications','Traite les demandes d’installation, de suppression et d’énumération pour le logiciel déployé au moyen de la stratégie de groupe. Si le service est désactivé, les utilisateurs ne pourront pas installer, supprimer ou énumérer le logiciel déployé au moyen de la stratégie de groupe. Si ce service est désactivé, tous les services qui en dépendent explicitement ne pourront pas démarrer.','Stopped','Manual'),
(2125,2,'AppReadiness','Préparation des applications','Prépare les applications pour la première connexion d’un utilisateur sur cet ordinateur et lors de l’ajout de nouvelles applications.','Stopped','Manual'),
(2126,2,'AppVClient','Microsoft App-V Client','Manages App-V users and virtual applications','Stopped','Disabled'),
(2127,2,'AppXSvc','Service de déploiement AppX (AppXSVC)','Assure la prise en charge de l’infrastructure pour le déploiement d’applications du Store. Ce service démarre à la demande. S’il est désactivé, les applications du Store ne sont pas déployées sur le système et peuvent ne pas fonctionner correctement.','Stopped','Auto'),
(2128,2,'ApxSvc','Service proxy de périphérique audio virtuel Windows','Gère les périphériques audio virtuels pour les programmes Windows.  Si ce service est arrêté, les périphériques audio virtuels ne fonctionneront pas correctement.  Si ce service est désactivé, les services qui en dépendent explicitement ne pourront pas démarrer','Stopped','Manual'),
(2129,2,'AssignedAccessManagerSvc','Service AssignedAccessManager','Le service AssignedAccessManager prend en charge l\'expérience Borne dans Windows.','Stopped','Manual'),
(2130,2,'AudioEndpointBuilder','Générateur de points de terminaison du service Audio Windows','Gère les périphériques audio pour le service Audio Windows. Si ce service est arrêté, les périphériques et les effets audio ne fonctionnent pas correctement. Si ce service est désactivé, tous les services qui en dépendent explicitement ne peuvent pas démarrer.','Running','Auto'),
(2131,2,'Audiosrv','Audio Windows','Gère les périphériques audio pour les programmes compatibles Windows. Si ce service est arrêté, les périphériques et les effets audio ne fonctionneront pas correctement. S’il est désactivé, les services qui en dépendent explicitement ne démarreront pas','Running','Auto'),
(2132,2,'autotimesvc','Heure cellulaire','Ce service définit l\'heure en fonction des messages NITZ à partir d\'un réseau mobile.','Stopped','Manual'),
(2133,2,'AxInstSV','Programme d’installation ActiveX (AxInstSV)','Valide le contrôle de compte d’utilisateur pour l’installation des contrôles ActiveX depuis Internet et permet de gérer leur installation d’après les paramètres de la stratégie de groupe. Ce service est démarré sur demande et, s’il est désactivé, l’installation des contrôles ActiveX se comporte conformément aux paramètres par défaut du navigateur.','Stopped','Manual'),
(2134,2,'BDESVC','Service de chiffrement de lecteur BitLocker','BDESVC héberge le service de chiffrement de lecteur BitLocker. Le chiffrement de lecteur BitLocker fournit un démarrage sécurisé pour le système d’exploitation, ainsi qu’un chiffrement total du volume pour le système d’exploitation, les volumes fixes ou les volumes amovibles. Ce service permet à BitLocker d’inviter les utilisateurs à effectuer diverses actions liées aux volumes montés, et déverrouille les volumes automatiquement sans intervention de l’utilisateur. En outre, il stocke les informations de récupération dans Active Directory, s’il est disponible, et, si nécessaire, garantit que les certificats de récupération les plus récents sont utilisés. L’arrêt ou la désactivation du service empêche les utilisateurs de tirer parti de cette fonctionnalité.','Stopped','Manual'),
(2135,2,'BFE','Moteur de filtrage de base','Le moteur de filtrage de base est un service qui gère les stratégies de pare-feu et de sécurité IP (IPsec), et qui implémente le filtrage en mode utilisateur. L’arrêt ou la désactivation du service Moteur de filtrage de base diminue significativement la sécurité du système et aboutit également à un fonctionnement imprévisible des applications de gestion et de pare-feu IPsec.','Running','Auto'),
(2136,2,'BITS','Service de transfert intelligent en arrière-plan','Transfère des fichiers en arrière-plan en utilisant la bande passante réseau inactive. Si le service est désactivé, toutes les applications dépendant du service de transfert intelligent d’arrière-plan, telles que Windows Update ou MSN Explorer, ne pourront plus télécharger des programmes ni d’autres informations.','Stopped','Manual'),
(2137,2,'BrokerInfrastructure','Service d’infrastructure des tâches en arrière-plan','Service d’infrastructure Windows qui contrôle les tâches en arrière-plan qui peuvent s’exécuter sur le système.','Running','Auto'),
(2138,2,'BTAGService','Service de passerelle audio Bluetooth','Service prenant en charge le rôle de passerelle audio du profil mains libres Bluetooth.','Running','Manual'),
(2139,2,'BthAvctpSvc','Service AVCTP','Ceci est le service de protocole de transport de contrôle audio vidéo','Running','Manual'),
(2140,2,'bthserv','Service de prise en charge Bluetooth','Le service Bluetooth prend en charge la découverte et l’association d’appareils Bluetooth distants. L’arrêt ou la désactivation de ce service peut entraîner un dysfonctionnement des appareils Bluetooth déjà installés et peut empêcher la découverte et l’association de nouveaux appareils.','Running','Manual'),
(2141,2,'camsvc','Service Gestionnaire d’accès aux fonctionnalités','Fournit des fonctionnalités pour la gestion de l’accès des applications UWP aux fonctionnalités de l’application, ainsi que pour la vérification de l’accès d\'une application aux fonctionnalités de l’application spécifique','Running','Auto'),
(2142,2,'CDPSvc','Service de plateforme des appareils connectés','Ce service est utilisé pour les scénarios plateforme d’appareils connectés','Running','Auto'),
(2143,2,'CertPropSvc','Propagation du certificat','Copie des certificats utilisateur et des certificats racines à partir de cartes à puce dans le magasin de certificats de l’utilisateur actuel, détecte quand une carte à puce est insérée dans un lecteur de cartes à puce, et, si nécessaire, installe le minipilote Plug and Play de cartes à puce.','Running','Manual'),
(2144,2,'ClipSVC','Service de licences de client (ClipSVC)','Permet la prise en charge de l\'infrastructure de Microsoft Store. Ce service démarre à la demande. S\'il est désactivé, les applications achetées via le Microsoft Store ne se comportent pas correctement.','Stopped','Manual'),
(2145,2,'cloudidsvc','Service d’identité de Microsoft Cloud','Prend en charge les intégrations avec Microsoft Cloud Identity services.  Si elle est désactivée, les restrictions de locataire ne seront pas appliquées correctement.','Stopped','Manual'),
(2146,2,'COMSysApp','Application système COM+','Gère la configuration et le suivi des composants de base COM+ (Component Object Model). Si le service est arrêté, la plupart des composants de base COM+ ne fonctionneront pas correctement. Si ce service est désactivé, les services qui en dépendent de manière explicite ne pourront pas démarrer.','Stopped','Manual'),
(2147,2,'CoreMessagingRegistrar','CoreMessaging','Manages communication between system components.','Running','Auto'),
(2148,2,'cplspcon','Intel(R) Content Protection HDCP Service','Intel(R) Content Protection HDCP Service - enables communication with Content Protection HDCP HW','Running','Auto'),
(2149,2,'CryptSvc','Services de chiffrement','Fournit trois services de gestion : le service de base de données de catalogues, qui confirme les signatures des fichiers Windows et autorise l’installation de nouveaux programmes, le service de racine protégée, qui ajoute et supprime les certificats d’autorité de certification racines approuvés sur cet ordinateur, et le service de mise à jour de certificats racines automatique, qui extrait les certificats racines à partir de Windows Update et autorise les scénarios tels que SSL. Si ce service est arrêté, les services de gestion ne fonctionneront pas correctement. Si ce service est désactivé, les services en dépendant explicitement ne démarreront pas.','Running','Auto'),
(2150,2,'CscService','Fichiers hors connexion','Le service Fichiers hors connexion effectue des activités de maintenance sur le cache Fichiers hors connexion, répond aux événements d’ouverture et de fermeture de session des utilisateurs, implémente les données internes de l’API public, et distribue aux utilisateurs intéressés les événements pertinents relatifs aux activités Fichiers hors connexion et aux modifications apportées en mémoire cache.','Stopped','Manual'),
(2151,2,'DcomLaunch','Lanceur de processus serveur DCOM','Le service DCOMLAUNCH lance les serveurs COM et DCOM en réponse aux demandes d’activation d’objets. Si ce service est arrêté ou désactivé, les programmes qui utilisent COM ou DCOM ne fonctionnent pas correctement. Il est fortement recommandé d’exécuter le service DCOMLAUNCH.','Running','Auto'),
(2152,2,'dcsvc','Service de configuration (DC) déclaré','Traiter les documents de configuration déclarés reçus de GPM et d’autres canaux et effectuer des configurations sur l’appareil','Stopped','Manual'),
(2153,2,'defragsvc','Optimiser les lecteurs','Permet à l’ordinateur de fonctionner plus efficacement en optimisant les fichiers sur les lecteurs de stockage.','Stopped','Manual'),
(2154,2,'DeviceAssociationService','Service d’association de périphérique','Permet de coupler des périphériques câblés ou sans fil au système.','Running','Manual'),
(2155,2,'DeviceInstall','Service d’installation de périphérique','Permet à l’ordinateur de reconnaître et d’adapter les modifications matérielles avec peu ou pas du tout d’intervention de l’utilisateur. Arrêter ou désactiver ce service provoque une instabilité du système.','Running','Manual'),
(2156,2,'DevQueryBroker','Service Broker de découverte en arrière-plan DevQuery','Permet aux applications de découvrir les périphériques avec une tâche en arrière-plan','Running','Manual'),
(2157,2,'Dhcp','Client DHCP','Inscrit et met à jour les adresses IP et les enregistrements DNS pour cet ordinateur. Si ce service est arrêté, cet ordinateur ne recevra pas d’adresses IP et de mises à jour DNS dynamiques. Si ce service est désactivé, tous les services qui en dépendent explicitement ne pourront pas démarrer.','Running','Auto'),
(2158,2,'diagsvc','Diagnostic Execution Service','Executes diagnostic actions for troubleshooting support','Stopped','Manual'),
(2159,2,'DiagTrack','Expériences des utilisateurs connectés et télémétrie','Le service Expériences des utilisateurs connectés et télémétrie offre des fonctionnalités qui prennent en charge les expériences des utilisateurs connectés et in-app. En outre, ce service gère la collecte et la transmission des informations de diagnostic et d\'utilisation en fonction des événements (afin d\'améliorer l\'expérience et la qualité de la plateforme Windows) lorsque les paramètres des options de confidentialité des diagnostics et de l\'utilisation sont activés sous Commentaires et diagnostics.','Running','Auto'),
(2160,2,'DialogBlockingService','DialogBlockingService','Boîte de dialogue blocage du service','Stopped','Disabled'),
(2161,2,'DispBrokerDesktopSvc','Service de stratégie d\'affichage','Gère la connexion et la configuration des affichages locaux et distants','Running','Auto'),
(2162,2,'DisplayEnhancementService','Service d\'amélioration de l\'affichage','Service permettant de gérer l\'amélioration de l\'affichage, tel que le contrôle de la luminosité.','Running','Manual'),
(2163,2,'DmEnrollmentSvc','Service d\'inscription de la gestion des périphériques','Assure les activités d\'inscription de périphériques de la gestion des périphériques.','Stopped','Manual'),
(2164,2,'dmwappushservice','Service de routage de messages Push du protocole WAP (Wireless Application Protocol) de gestion des appareils','Achemine les messages Push du protocole WAP (Wireless Application Protocol) reçus par l\'appareil et synchronise les sessions de gestion des appareils','Stopped','Auto'),
(2165,2,'Dnscache','Client DNS','Le service client DNS (dnscache) envoie des requêtes DNS (Domain Name System), met en cache les résultats de la requête et inscrit le nom complet de l’ordinateur sur le réseau. Ce service ne peut pas être arrêté.','Running','Auto'),
(2166,2,'DolbyDAXAPI','Dolby DAX API Service','Dolby DAX API Service is used by Dolby DAX applications to control Dolby Atmos components in the system.','Running','Auto'),
(2167,2,'DolbyFusionAPI','Dolby Fusion API Service','Dolby Fusion API Service is used by Dolby Fusion applications to control Dolby Fusion components in the system.','Running','Auto'),
(2168,2,'DoSvc','Optimisation de livraison','Effectue des tâches d\'optimisation de distribution de contenu','Running','Auto'),
(2169,2,'dot3svc','Configuration automatique de réseau câblé','Le service Wired AutoConfig (DOT3SVC) est responsable de l’exécution de l’authentification IEEE 802.1X sur les interfaces Ethernet. Si votre déploiement de réseau câblé actuel applique l’authentification 802.1X, le service DOT3SVC doit être configuré de façon à s’exécuter pour l’établissement de la connectivité de Couche 2 et/ou fournir l’accès aux ressources réseau. Les réseaux câblés qui n’appliquent pas l’authentification 802.1X ne sont pas concernés par le service DOT3SVC.','Stopped','Manual'),
(2170,2,'DPS','Service de stratégie de diagnostic','Le service de stratégie de diagnostic permet la détection, le dépannage et la résolution de problèmes pour les composants de Windows. Si ce service est arrêté, les diagnostics ne fonctionnent plus.','Running','Auto'),
(2171,2,'dptftcs','Intel(R) Dynamic Tuning Technology Telemetry Service','Intel(R) Dynamic Tuning Technology Telemetry Service','Running','Auto'),
(2172,2,'DsmSvc','Gestionnaire d’installation de périphérique','Active la détection, le téléchargement et l’installation du logiciel associé au périphérique. Si ce service est désactivé, les périphériques risquent d’être configurés avec un logiciel obsolète et de ne pas fonctionner correctement.','Stopped','Manual'),
(2173,2,'DsSvc','Service de partage des données','Fournit l\'intermédiation des données entre les applications.','Running','Manual'),
(2174,2,'DusmSvc','Consommation des données','Consommation des données du réseau, limite de données, limiter les données d’arrière-plan, connexions réseau limitées.','Running','Auto'),
(2175,2,'EapHost','Protocole EAP (Extensible Authentication Protocol)','Le service EAP (Extensible Authentication Protocol) permet d’authentifier le réseau dans des scénarios tels que des réseaux câblés et sans fil 802.1x, des réseaux privés virtuels et NAP (Network Access Protection). Ce service fournit également des API qui sont utilisées par les clients d’accès à distance, notamment les clients sans fil et VPN, lors de l’authentification. Si vous désactivez ce service, cet ordinateur ne pourra pas accéder aux réseaux qui nécessitent l’authentification EAP.','Stopped','Manual'),
(2176,2,'edgeupdate','Microsoft Edge Update Service (edgeupdate)','Maintient votre logiciel Microsoft à jour. Si ce service est désactivé ou arrêté, votre logiciel Microsoft n\'est pas mis à jour, ce qui signifie que les potentielles failles de sécurité peuvent ne pas être corrigées et que certaines fonctionnalités risquent de ne pas être opérationnelles. Ce service se désinstalle de lui-même si aucun logiciel Microsoft ne l\'utilise.','Stopped','Auto'),
(2177,2,'edgeupdatem','Microsoft Edge Update Service (edgeupdatem)','Maintient votre logiciel Microsoft à jour. Si ce service est désactivé ou arrêté, votre logiciel Microsoft n\'est pas mis à jour, ce qui signifie que les potentielles failles de sécurité peuvent ne pas être corrigées et que certaines fonctionnalités risquent de ne pas être opérationnelles. Ce service se désinstalle de lui-même si aucun logiciel Microsoft ne l\'utilise.','Stopped','Manual'),
(2178,2,'EFS','Système de fichiers EFS (Encrypting File System)','Fournit la technologie de chiffrement des fichiers de base utilisée pour stocker les fichiers chiffrés sur les volumes NTFS. Si ce service est arrêté ou désactivé, les applications n’auront pas accès aux fichiers chiffrés.','Stopped','Manual'),
(2179,2,'embeddedmode','Mode incorporé','Le service Mode incorporé active les scénarios associés aux applications d’arrière-plan. La désactivation de ce service empêche l’activation de ces applications.','Stopped','Manual'),
(2180,2,'EntAppSvc','Service de gestion des applications d\'entreprise','Permet la gestion des applications d\'entreprise.','Stopped','Manual'),
(2181,2,'EPDService','ELAN PST Service','Service for ELAN TrackPoint Driver','Running','Auto'),
(2182,2,'EventLog','Journal d’événements Windows','Ce service gère les événements et les journaux d’événements. Il prend en charge l’enregistrement des événements, les requêtes sur les événements, l’abonnement aux événements, l’archivage des journaux d’événements et la gestion des métadonnées d’événements. Il peut afficher des événements en XML et en format de texte brut. L’arrêt de ce service peut compromettre la sécurité et la fiabilité du système.','Running','Auto'),
(2183,2,'EventSystem','Système d’événement COM+','Prend en charge le service de notification d’événements système (SENS, System Event Notification Service), qui fournit une distribution automatique d’événements aux composants COM (Component Object Model) abonnés. Si le service est arrêté, SENS sera fermé et ne pourra fournir des informations d’ouverture et de fermeture de session. Si ce service est désactivé, le démarrage de tout service qui en dépend explicitement échouera.','Running','Auto'),
(2184,2,'fdPHost','Hôte du fournisseur de découverte de fonctions','Le service FDPHOST héberge les fournisseurs de découverte de réseau de découverte de fonction (FD). Ces fournisseurs de découverte de fonction fournissent des services de découverte de réseau pour les protocoles SSDP (Simple Services Discovery Protocol) et WS-D (Web Services - Discovery). L’arrêt ou la désactivation du service FDPHOST désactivera la découverte de réseau pour ces protocoles lors de l’utilisation de la découverte de fonction. Lorsque ce service n’est pas disponible, les services réseau qui utilisent la découverte de fonction et qui dépendent de ces protocoles de découverte ne pourront pas trouver des périphériques ou des ressources réseau.','Stopped','Manual'),
(2185,2,'FDResPub','Publication des ressources de découverte de fonctions','Publie cet ordinateur et les ressources qui y sont attachées, de façon à ce que leur découverte soit possible sur le réseau. Si ce service est arrêté, les ressources réseau ne sont plus publiées et ne seront donc pas découvertes par les autres ordinateurs du réseau.','Stopped','Manual'),
(2186,2,'fhsvc','Service d’historique des fichiers','Protège les fichiers utilisateurs des pertes accidentelles en les copiant dans un emplacement de sauvegarde.','Stopped','Manual'),
(2187,2,'FontCache','Service de cache de police Windows','Optimise les performances des applications en mettant en cache les données des polices communément utilisées. Les applications démarrent ce service s’il n’est pas déjà en fonctionnement. Il peut être désactivé ; il en résulte cependant une dégradation des performances des applications.','Running','Auto'),
(2188,2,'FrameServer','Serveur de trame de la Caméra Windows','Permettre à plusieurs clients d’accéder aux trames vidéo des appareils photo.','Stopped','Manual'),
(2189,2,'FrameServerMonitor','Moniteur de serveur de trame Caméra Windows','Surveille l’intégrité et l’état du service serveur de trames de caméra Windows.','Stopped','Manual'),
(2190,2,'GameInputSvc','GameInput Service','Enables keyboards, mice, gamepads, and other input devices to be used with the GameInput API.','Stopped','Manual'),
(2191,2,'GoogleChromeElevationService','Google Chrome Elevation Service (GoogleChromeElevationService)','Fournit des services de chiffrement et un moyen sécurisé de restaurer Google Chrome si la version est ancienne. Si ce service est désactivé,  pourrait perdre l\'accès aux données chiffrées, et  pourrait ne pas pouvoir se restaurer.','Stopped','Manual'),
(2192,2,'GoogleUpdaterInternalService144.0.7547.0','Service interne de mise à jour Google (GoogleUpdaterInternalService144.0.7547.0)','Ce service maintient à jour votre logiciel Google, ce qui n\'est pas le cas s\'il est désactivé ou interrompu. Toute faille de sécurité susceptible d\'apparaître ne pourra alors pas être corrigée, et il est possible que certaines options ne fonctionneront pas. Ce service se désinstalle automatiquement quand aucun logiciel Google ne l\'utilise.','Stopped','Auto'),
(2193,2,'GoogleUpdaterService144.0.7547.0','Service de mise à jour Google (GoogleUpdaterService144.0.7547.0)','Ce service maintient à jour votre logiciel Google, ce qui n\'est pas le cas s\'il est désactivé ou interrompu. Toute faille de sécurité susceptible d\'apparaître ne pourra alors pas être corrigée, et il est possible que certaines options ne fonctionneront pas. Ce service se désinstalle automatiquement quand aucun logiciel Google ne l\'utilise.','Stopped','Auto'),
(2194,2,'gpsvc','Client de stratégie de groupe','Le service est responsable de l’application des paramètres configurés par les administrateurs pour l’ordinateur et pour les utilisateurs via le composant de stratégie de groupe. Si le service est désactivé, les paramètres ne seront pas appliqués, et les applications et les composants ne seront pas gérables par la stratégie de groupe. Tout composant ou application qui dépend du composant de stratégie de groupe risque de ne pas fonctionner si le service est désactivé.','Stopped','Auto'),
(2195,2,'GraphicsPerfSvc','GraphicsPerfSvc','Graphics performance monitor service','Stopped','Manual'),
(2196,2,'hidserv','Service du périphérique d’interface utilisateur','Active et maintient l’utilisation des boutons actifs sur le clavier, les contrôles à distance et d’autres périphériques multimédias. Nous vous recommandons de veiller à ce que ce service soit constamment en cours d’exécution.','Stopped','Manual'),
(2197,2,'hpatchmon','Hotpatch Monitoring Service','Monitors Hotpatch ETW Trace providers and reports failures.','Stopped','Manual'),
(2198,2,'HvHost','Service d\'hôte HV','Propose une interface pour l’hyperviseur Hyper-V afin de fournir des compteurs de performance par partition au système d’exploitation hôte.','Running','Manual'),
(2199,2,'IBMPMSVC','Lenovo PM Service',NULL,'Running','Auto'),
(2200,2,'icssvc','Service Point d\'accès sans fil mobile Windows','Permet de partager une connexion de données cellulaires avec un autre appareil.','Stopped','Manual'),
(2201,2,'IKEEXT','Modules de génération de clés IKE et AuthIP','Le service IKEEXT héberge les modules de génération de clés IKE (Internet Key Exchange) et AuthIP (Authenticated Internet Protocol). Ces modules de génération de clés sont utilisés pour l’authentification et l’échange de clés dans la sécurité IP (IPsec). L’arrêt ou la désactivation du service IKEEXT entraînera la désactivation de l’échange de clés IKE et AuthIP avec des ordinateurs homologues. IPsec est généralement configuré pour utiliser IKE ou AuthIP ; par conséquent, l’arrêt ou la désactivation du service IKEEXT risque de conduire à la défaillance d’IPsec et de compromettre la sécurité du système. Il est fortement recommandé d’activer l’exécution du service IKEEXT.','Running','Auto'),
(2202,2,'InstallService','Installation du service Microsoft Store','Offre une prise en charge de l\'infrastructure pour le Microsoft Store.  Ce service est lancé à la demande, et les installations ne fonctionneront pas correctement, s\'il est désactivé.','Running','Manual'),
(2203,2,'IntelAudioService','Intel(R) Audio Service',NULL,'Running','Auto'),
(2204,2,'InventorySvc','Service d’Appraisal inventaire et compatibilité','Ce service effectue l’inventaire système d’arrière-plan, la vérification de la compatibilité et la maintenance utilisées par de nombreux composants système.','Running','Auto'),
(2205,2,'ipfsvc','Intel(R) Innovation Platform Framework Service','Intel(R) Innovation Platform Framework Service','Running','Auto'),
(2206,2,'iphlpsvc','Assistance IP','Fournit une connectivité de tunnel à l’aide des technologies de transition IPv6 (6to4, ISATAP, Proxy de port et Teredo) et IP-HTTPS. Si ce service est arrêté, l’ordinateur ne disposera pas des avantages de la connectivité améliorée offerts par ces technologies.','Running','Auto'),
(2207,2,'IpxlatCfgSvc','Service de configuration de conversion IP','Configure et permet la conversion de v4 en v6 et vice versa','Stopped','Manual'),
(2208,2,'jhi_service','Intel(R) Dynamic Application Loader Host Interface Service','Intel(R) Dynamic Application Loader Host Interface Service - Allows applications to access the local Intel (R) DAL','Running','Auto'),
(2209,2,'KeyIso','Isolation de clé CNG','Le service d’isolation de clé CNG est hébergé dans le processus LSA. Le service fournit une isolation de processus de clé aux clés privés et aux opérations de chiffrement associées, conformément aux critères communs. Le service stocke et utilise des clés à long terme dans le cadre d’un processus sécurisé répondant aux exigences des critères communs.','Running','Manual'),
(2210,2,'KtmRm','Service KtmRm pour Distributed Transaction Coordinator','Coordonne les transactions entre Distributed Transaction Coordinator (MSDTC) et le gestionnaire de transactions du noyau (KTN). S’il n’est pas requis, il est recommandé que ce service reste arrêté. S’est requis, MSDTC et KTM démarrent ce service automatiquement. Si ce service est désactivé, toute transaction MSDTC interagissant avec un gestionnaire de transactions du noyau échoue et tout service qui en dépend de façon explicite ne parvient pas à démarrer.','Stopped','Manual'),
(2211,2,'LanmanServer','Serveur','Prend en charge le partage de fichiers, d’impression et des canaux nommés via le réseau pour cet ordinateur. Si ce service est arrêté, ces fonctions ne seront pas disponibles. Si ce service est désactivé, les services qui en dépendent ne pourront pas démarrer.','Running','Auto'),
(2212,2,'LanmanWorkstation','Station de travail','Crée et maintient des connexions de réseau client à des serveurs distants à l’aide du protocole SMB. Si ce service est arrêté, ces connexions ne seront pas disponibles. Si ce service est désactivé, les services qui en dépendent explicitement ne pourront pas démarrer.','Running','Auto'),
(2213,2,'LenovoBrightCtrl','Lenovo Display Brightness Control Service',NULL,'Stopped','Disabled'),
(2214,2,'LenovoSmartStandby','Lenovo Smart Standby','Provides the functionalities of Lenovo Smart Standby.','Running','Auto'),
(2215,2,'LenovoVantageService','Critical Service for Lenovo Vantage',NULL,'Running','Auto'),
(2216,2,'LenovoVisionService','Lenovo Vision Service','Lenovo Vision Service','Running','Auto'),
(2217,2,'lfsvc','Service de géolocalisation','Ce service surveille l\'emplacement actuel du système et gère les limites géographiques (un emplacement géographique accompagné d\'événements associés). Si vous désactivez ce service, les applications ne pourront pas utiliser ni recevoir de notification pour la géolocalisation ou des limites géographiques.','Running','Manual'),
(2218,2,'LicenseManager','Serveur Gestionnaire de licences Windows','Offre une prise en charge de l\'infrastructure pour le Microsoft Store.  Ce service est lancé à la demande, et le contenu acquis via le Microsoft Store ne fonctionnera pas correctement, s\'il est désactivé.','Running','Manual'),
(2219,2,'LITSSVC','Lenovo Intelligent Thermal Solution Service',NULL,'Running','Auto'),
(2220,2,'lltdsvc','Mappage de découverte de topologie de la couche de liaison','Crée un mappage réseau, consistant en informations sur la topologie des ordinateurs et des périphériques (connectivité) et en métadonnées décrivant chaque ordinateur et chaque périphérique. Si ce service est désactivé, le mappage réseau ne fonctionne pas correctement.','Stopped','Manual'),
(2221,2,'lmhosts','Assistance NetBIOS sur TCP/IP','Prend en charge le service NetBIOS sur TCP/IP (NetBT) et la résolution de noms NetBIOS pour les clients présents sur le réseau, ce qui permet aux utilisateurs de partager des fichiers, d’imprimer et d’ouvrir des sessions sur le réseau. Si ce service est arrêté, ces fonctions risquent de ne pas être disponibles. Si ce service est désactivé, les services qui en dépendent explicitement ne pourront pas démarrer.','Running','Manual'),
(2222,2,'LocalKdc','Centre local de distribution de clés Kerberos','Ce service permet aux utilisateurs de se connecter à l’ordinateur local à l’aide du protocole d’authentification Kerberos. Si ce service est arrêté, les utilisateurs ne pourront pas se connecter à l’ordinateur local. Si ce service est désactivé, les services qui en dépendent explicitement ne pourront pas démarrer.','Stopped','Manual'),
(2223,2,'LPlatSvc','Lenovo Platform Service',NULL,'Stopped','Auto'),
(2224,2,'LSM','LSM',NULL,'Running','Unknown'),
(2225,2,'LxpSvc','Service d\'expérience linguistique','Fournit une prise en charge de l\'infrastructure permettant de déployer et de configurer des ressources Windows localisées. Ce service est démarré à la demande et, s\'il est désactivé, des langues Windows supplémentaires ne sont pas déployées sur le système et Windows risque de ne pas fonctionner correctement.','Stopped','Manual'),
(2226,2,'MapsBroker','Gestionnaire des cartes téléchargées','Service Windows pour l’accès des applications aux cartes téléchargées. Ce service est démarré à la demande par l’application, qui accède aux cartes téléchargées. La désactivation de ce service empêche les applications d’accéder aux cartes.','Stopped','Auto'),
(2227,2,'McmSvc','Service de gestion de la connectivité mobile','Ce service assure la gestion des profils pour les modules de connectivité mobile','Stopped','Manual'),
(2228,2,'McpManagementService','McpManagementService','Service de gestion Impression universelle','Stopped','Manual'),
(2229,2,'MDCoreSvc','Microsoft Defender Service de base','Surveille la disponibilité, l’intégrité et les performances de divers composants de sécurité','Running','Auto'),
(2230,2,'MicrosoftEdgeElevationService','Microsoft Edge Elevation Service (MicrosoftEdgeElevationService)','Fournit des privilèges élevés pour Microsoft Edge.','Stopped','Manual'),
(2231,2,'midisrv','Service MIDI de Windows','Service principal des services WINDOWS MIDI pour le routage des messages MIDI 1.0 et MIDI 2.0 et l’énumération des appareils','Running','Manual'),
(2232,2,'MozillaMaintenance','Mozilla Maintenance Service','Le service de maintenance de Mozilla s’assure que vous avez la dernière version la plus sûre de Mozilla Firefox sur votre ordinateur. Garder Firefox à jour est très important pour votre sécurité en ligne et Mozilla vous recommande vivement de laisser ce service activé.','Stopped','Manual'),
(2233,2,'mpssvc','Pare-feu Windows Defender','Le Pare-feu Windows Defender vous aide à protéger votre ordinateur en empêchant les utilisateurs non autorisés d\'accéder à votre ordinateur via Internet ou un réseau.','Running','Auto'),
(2234,2,'MSDTC','Coordinateur de transactions distribuées','Coordonne les transactions qui comportent plusieurs gestionnaires de ressources, tels que des bases de données, des files d’attente de messages net des systèmes de fichiers. Si ce service est arrêté, ces transactions échoueront. S’il est désactivé, le démarrage de tout service qui en dépend explicitement échouera.','Stopped','Manual'),
(2235,2,'MSiSCSI','Service Initiateur iSCSI de Microsoft','Gère les sessions iSCSI (Internet SCSI) à partir de cet ordinateur sur les périphériques cible iSCSI distants. Si ce service est arrêté, l’ordinateur ne pourra plus ouvrir de session sur les cibles iSCSI ni y accéder. S’il est désactivé, tous les services qui dépendent explicitement de lui ne pourront plus démarrer.','Stopped','Manual'),
(2236,2,'msiserver','Windows Installer','Ajoute, modifie et supprime des applications fournies en tant que package Windows Installer (*.msi, *.msp, *.appx). Si ce service est désactivé, les services qui en dépendent explicitement ne démarreront pas.','Stopped','Manual'),
(2237,2,'MsKeyboardFilter','Filtre clavier Microsoft','Contrôle le filtrage et le mappage des touches','Stopped','Disabled'),
(2238,2,'NaturalAuthentication','Authentification naturelle','Service d’agrégation de signaux qui évalue les signaux en fonction de l’heure, de la géolocalisation du réseau, des facteurs bluetooth et cdf. Les fonctionnalités prises en charge sont les stratégies Déverrouillage d’appareil, Verrouillage dynamique et Dynamo MDM.','Stopped','Manual'),
(2239,2,'NcaSvc','Assistant Connectivité réseau','Fournit la notification du statut DirectAccess aux composants de l’interface utilisateur','Stopped','Manual'),
(2240,2,'NcbService','Service Broker pour les connexions réseau','Connexions du service Broker qui permettent aux applications empaquetées du Microsoft Store de recevoir des notifications d’Internet.','Running','Manual'),
(2241,2,'NcdAutoSetup','Configuration automatique des périphériques connectés au réseau','Le service Configuration automatique des périphériques connectés au réseau supervise et installe les périphériques qualifiés qui se connectent à un réseau qualifié. L’arrêt ou la désactivation de ce service empêchent Windows de découvrir et installer automatiquement des périphériques connectés au réseau qualifié. Les utilisateurs peuvent quand même ajouter manuellement des périphériques connectés au réseau à un ordinateur via l’interface utilisateur.','Stopped','Manual'),
(2242,2,'Netlogon','Netlogon','Maintient un canal sécurisé entre cet ordinateur et le contrôleur de domaine pour authentifier les utilisateurs et les services. Si ce service est arrêté, l’ordinateur peut ne pas authentifier les utilisateurs et les services et le contrôleur de domaine ne peut pas inscrire les enregistrements DNS. Si ce service est désactivé, tout service qui en dépend explicitement ne pourra pas démarrer.','Stopped','Manual'),
(2243,2,'Netman','Connexions réseau','Prend en charge les objets dans le dossier Connexions réseau et accès à distance, dans lequel vous pouvez afficher à la fois les connexions du réseau local et les connexions à distance.','Stopped','Manual'),
(2244,2,'netprofm','Service Liste des réseaux','Identifie les réseaux auxquels l’ordinateur s’est connecté, collecte et stocke les propriétés de ces réseaux, et signale aux applications toute modification des propriétés.','Running','Manual'),
(2245,2,'NetSetupSvc','NetSetupSvc',NULL,'Running','Unknown'),
(2246,2,'NetTcpPortSharing','Service de partage de ports Net.Tcp','Fournit la possibilité de partager des ports TCP sur le protocole net.tcp.','Stopped','Disabled'),
(2247,2,'NgcCtnrSvc','Conteneur Microsoft Passport','Gère les clés d\'identité d\'utilisateur local servant à authentifier l\'utilisateur auprès des fournisseurs d\'identité, ainsi que les cartes à puce virtuelles du module de plateforme sécurisée (TPM). Si ce service est désactivé, les clés d\'identité d\'utilisateur local et les cartes à puce virtuelles TPM ne seront pas accessibles. Nous vous recommandons de ne pas reconfigurer ce service.','Stopped','Manual'),
(2248,2,'NgcSvc','Microsoft Passport','Assure l\'isolation des processus pour les clés de chiffrement servant à l\'authentification auprès des fournisseurs d\'identité associés à un utilisateur. Si ce service est désactivé, les fonctions d\'utilisation et de gestion de ces clés, telles que l\'ouverture de session et l\'authentification unique pour les applications et les sites web, ne seront pas disponibles. Ce service démarre et s\'arrête automatiquement. Il est recommandé de ne pas le reconfigurer.','Stopped','Manual'),
(2249,2,'NlaSvc','Connaissance des emplacements réseau','Collecte et stocke les informations de configuration du réseau, puis notifie les programmes en cas de modification de ces informations. Si ce service est arrêté, les informations de configuration risquent de ne pas être disponibles. Si ce service est désactivé, les services qui en dépendent explicitement ne pourront pas démarrer.','Stopped','Manual'),
(2250,2,'nsi','Service Interface du magasin réseau','Ce service fournit des notifications réseau (ajout/suppression d’interface, etc.) aux clients en mode utilisateur. L’arrêt de ce service entraîne la perte de la connectivité réseau. Si ce service est désactivé, les autres services qui en dépendent explicitement ne pourront pas démarrer.','Running','Auto'),
(2251,2,'PcaSvc','Service de l’Assistant Compatibilité des programmes','Ce service fournit une prise en charge de l’Assistant Compatibilité des programmes. Cet Assistant surveille les programmes installés et exécutés par l’utilisateur et détecte les problèmes de compatibilité connus. Si ce service est arrêté, cet Assistant ne fonctionnera pas correctement.','Running','Auto'),
(2252,2,'PeerDistSvc','BranchCache','Ce service met en cache le contenu réseau à partir d’homologues sur le sous-réseau local.','Stopped','Manual'),
(2253,2,'perceptionsimulation','Service de simulation de perception Windows','Permet la simulation de perception spatiale, la gestion de la caméra virtuelle et la simulation d\'entrée spatiale.','Stopped','Manual'),
(2254,2,'PerfHost','Hôte de DLL de compteur de performance','Permet aux utilisateurs à distances et aux processus 64 bits d’interroger les compteurs de performances fournis par des DLL 32 bits. Si ce service est arrêté, seuls les utilisateurs locaux et les processus 32 bits peuvent interroger les compteurs fournis par des DLL 32 bits.','Stopped','Manual'),
(2255,2,'PhoneSvc','Service téléphonique','Gère l\'état de téléphonie de l\'appareil','Stopped','Manual'),
(2256,2,'pla','Journaux & alertes de performance','Le service des journaux et des alertes de performance collecte des données de performance sur des ordinateurs locaux ou distants, en se basant sur des paramètres de planification préconfigurés, puis écrit ces données dans un journal ou déclenche une alerte. Si ce service est arrêté, les informations de performance ne seront plus collectées. Si ce service est désactivé, tous les services qui en dépendent explicitement ne pourront plus démarrer.','Stopped','Manual'),
(2257,2,'PlugPlay','Plug-and-Play','Permet à l’ordinateur de reconnaître et d’adapter les modifications matérielles avec peu ou pas du tout d’intervention de l’utilisateur. Arrêter ou désactiver ce service provoque une instabilité du système.','Running','Manual'),
(2258,2,'PolicyAgent','Agent de stratégie IPsec','La sécurité du protocole Internet (IPSec) prend en charge l’authentification de l’homologue réseau, l’authentification de l’origine des données, l’intégrité des données, la confidentialité des données (chiffrement) et la protection de la relecture. Ce service met en œuvre des stratégies IPSec créées via le composant logiciel enfichable Stratégies de sécurité IP ou l’outil de ligne de commande « netsh ipsec ». Si vous arrêtez ce service, vous pourrez rencontrer des problèmes de connectivité réseau si votre stratégie nécessite des connexions IPSec. En outre, la gestion à distance du Pare-feu Windows Defender n’est pas disponible lorsque ce service est arrêté.','Running','Manual'),
(2259,2,'Power','Alimentation','Gère la stratégie d’alimentation et la remise de notification de stratégie d’alimentation.','Running','Auto'),
(2260,2,'PrintDeviceConfigurationService','Service de configuration du périphérique d’impression','Le service de configuration du périphérique d’impression gère l’installation des imprimantes IPP et UP. Si ce service est arrêté, toutes les installations d’imprimantes en cours peuvent être annulées.','Stopped','Manual'),
(2261,2,'PrintNotify','Extensions et notifications d’imprimante','Ce service ouvre les boîtes de dialogue d’impression personnalisée et gère les notifications d’une imprimante ou d’un serveur d’impression distant. Si vous désactivez ce service, vous ne pourrez plus voir les extensions ou notifications relatives aux imprimantes.','Stopped','Manual'),
(2262,2,'PrintScanBrokerService','PrintScanBrokerService','Assure la prise en charge des opérations privilégiées sécurisées requises par le spouleur faiblement privilégié.','Stopped','Manual'),
(2263,2,'ProfSvc','Service de profil utilisateur','Ce service est responsable du chargement et du déchargement des profils utilisateur. Si ce service est arrêté ou désactivé, les utilisateurs ne pourront plus se connecter ou se déconnecter, les applications pourront avoir des problèmes pour obtenir les données des utilisateurs, et les composants inscrits pour recevoir les notifications d’événements de profils ne les recevront pas.','Running','Auto'),
(2264,2,'PushToInstall','Service PushToInstall de Windows','Offre une prise en charge de l\'infrastructure pour le Microsoft Store.  Ce service est démarré automatiquement, et les installations distantes ne fonctionneront pas correctement, s\'il est désactivé.','Stopped','Manual'),
(2265,2,'QServiceEM05G','QServiceEM05G','QServiceEM05G','Running','Auto'),
(2266,2,'QUECTELDPRSVC','Quectel Mini DPR Service','Quectel Mini DPR Service','Running','Auto'),
(2267,2,'QuectelModemAuthSVC','Quectel Modem Auth Service(EM05G)','Quectel Modem Auth Service(EM05G)','Running','Auto'),
(2268,2,'QWAVE','Expérience audio-vidéo haute qualité Windows','qWave (Quality Windows Audio Video Experience) est une plateforme réseau destinée aux applications de flux AV (Audio Video) sur des réseaux domestiques IP. qWave améliore les performances et la fiabilité des flux AV en assurant la qualité de service (QoS) sur le réseau des applications AV. Cette plateforme fournit des mécanismes concernant le contrôle d’admission, l’analyse et la mise en œuvre des principes de protection des informations personnelles à l’exécution, la rétroaction des applications et la définition des priorités du trafic.','Stopped','Manual'),
(2269,2,'RasAuto','Gestionnaire des connexions automatiques d’accès à distance','Crée une connexion vers un réseau distant à chaque fois qu’un programme référence un nom ou une adresse DNS ou NetBIOS distant.','Stopped','Manual'),
(2270,2,'RasMan','Gestionnaire des connexions d’accès à distance','Gère les connexions d’accès à distance et les connexions de réseau privé virtuel (VPN) entre cet ordinateur et Internet ou d’autres réseaux distants. Si ce service est désactivé, les services qui en dépendent explicitement ne pourront pas démarrer.','Running','Manual'),
(2271,2,'refsdedupsvc','Service de déduplication ReFS','Service de déduplication et de compression des données ReFS pour suivre les modifications apportées aux fichiers et exécuter des tâches d’optimisation planifiées','Stopped','Manual'),
(2272,2,'RemoteAccess','Routage et accès distant','Offre aux entreprises des services de routage dans les environnements de réseau local ou étendu.','Stopped','Disabled'),
(2273,2,'RemoteRegistry','Registre à distance','Permet aux utilisateurs à distance de modifier les paramètres du Registre sur cet ordinateur. Si ce service est arrêté, le Registre ne pourra être modifié que par les utilisateurs de cet ordinateur. Si ce service est désactivé, tout service en dépendant explicitement ne démarrera pas.','Stopped','Disabled'),
(2274,2,'RetailDemo','Service de démo du magasin','Le service de démo du magasin contrôle l\'activité du périphérique pendant que celui-ci est en mode démo.','Stopped','Manual'),
(2275,2,'RmSvc','Service de gestion radio','Service de gestion radio et de mode Avion','Running','Manual'),
(2276,2,'RpcEptMapper','Mappeur de point de terminaison RPC','Résout les identificateurs des interfaces RPC en points de terminaison de transport. Si ce service est arrêté ou désactivé, les programmes utilisant des services d’appel de procédure distante (RPC) ne fonctionneront pas correctement.','Running','Auto'),
(2277,2,'RpcLocator','Localisateur d’appels de procédure distante (RPC)','Dans Windows 2003 et les versions antérieures de Windows, le service Localisateur d’appels de procédure distante (RPC) gère la base de données du service de nom RPC. Dans Windows Vista et les versions ultérieures de Windows, ce service ne fournit aucune fonctionnalité et est présent à des fins de compatibilité applicative.','Running','Manual'),
(2278,2,'RpcSs','Appel de procédure distante (RPC)','Le service RPCSS est le Gestionnaire de contrôle des services pour les serveurs COM et DCOM. Il traite les demandes d’activation d’objets, les résolutions d’exportateur d’objets et le nettoyage de la mémoire distribuée pour les serveurs COM et DCOM. Si ce service est arrêté ou désactivé, les programmes utilisant COM ou DCOM ne fonctionnent pas correctement. Il est fortement recommandé d’exécuter le service RPCSS.','Running','Auto'),
(2279,2,'RtkAudioUniversalService','Realtek Audio Universal Service','Realtek Audio Universal Service','Running','Auto'),
(2280,2,'SamSs','Gestionnaire de comptes de sécurité','Le démarrage de ce service signale à d’autres services que le Gestionnaire de comptes de sécurité est prêt à accepter des demandes. La désactivation de ce service empêchera d’autres services dans le système d’être prévenus lorsque le Gestionnaire de comptes de sécurité sera prêt, ce qui pourrait provoquer le démarrage incorrect de ces services. Ce service ne doit pas être désactivé.','Running','Auto'),
(2281,2,'SCardSvr','Carte à puce','Gère l’accès aux cartes à puce lues par cet ordinateur. Si ce service est arrêté, cet ordinateur ne pourra plus lire de cartes à puces. Si ce service est désactivé, tout service en dépendant explicitement ne démarrera pas.','Running','Manual'),
(2282,2,'ScDeviceEnum','Service d’énumération de périphériques de carte à puce','Crée des nœuds de périphériques logiciels pour tous les lecteurs de cartes à puce accessibles à une session donnée. Si ce service est désactivé, les API WinRT ne peuvent pas énumérer les lecteurs de cartes à puce.','Stopped','Manual'),
(2283,2,'Schedule','Planificateur de tâches','Permet à un utilisateur de configurer et de planifier des tâches automatisées sur cet ordinateur. Le service héberge également plusieurs tâches critiques du système Windows. Si ce service est arrêté ou désactivé, ces tâches ne seront pas exécutées à l’heure prévue. Si ce service est désactivé, tout service en dépendant explicitement ne démarrera pas.','Running','Auto'),
(2284,2,'SCPolicySvc','Stratégie de retrait de la carte à puce','Autorise le système à être configuré pour verrouiller le Bureau de l’utilisateur au moment du retrait de la carte à puce.','Stopped','Manual'),
(2285,2,'SDRSVC','Sauvegarde Windows','Sauvegarde Windows et fonctionnalités de restauration.','Stopped','Manual'),
(2286,2,'seclogon','Ouverture de session secondaire','Permet le démarrage des processus sous d’autres informations d’identification. Si ce service est arrêté, ce type d’ouverture de session sera indisponible. Si ce service est désactivé, tout service en dépendant explicitement ne démarrera pas.','Running','Manual'),
(2287,2,'SecurityHealthService','Service Sécurité Windows','Le service Sécurité Windows gère la protection unifiée des appareils et les informations d\'intégrité','Running','Manual'),
(2288,2,'SEMgrSvc','Gestionnaires des paiements et des éléments sécurisés NFC','Gère les paiements et les éléments sécurisés basés sur la communication en champ proche (NFC).','Stopped','Manual'),
(2289,2,'SENS','Service de notification d’événements système','Analyse les événements système et notifie leur existence aux abonnés du système d’événements COM+.','Running','Auto'),
(2290,2,'Sense','Sense',NULL,'Stopped','Manual'),
(2291,2,'SensorDataService','Service Données de capteur','Fournit les données d\'une variété de capteurs','Stopped','Manual'),
(2292,2,'SensorService','Service de capteur','Service pour les capteurs permettant de gérer différentes fonctionnalités. Gère l\'orientation de périphérique simple et l\'historique des capteurs. Charge le capteur d\'orientation de périphérique simple rapportant les changements d\'orientation du périphérique. Si le service est interrompu ou désactivé, le capteur d\'orientation de périphérique simple ne sera pas chargé et la rotation automatique n\'aura pas lieu. La collecte d\'historiques des capteurs sera également interrompue.','Running','Manual'),
(2293,2,'SensrSvc','Service de surveillance des capteurs','Surveille plusieurs capteurs pour exposer les données et s’adapter aux divers états utilisateur et du système. Si le service est arrêté ou désactivé, la brillance de l’affichage ne s’adaptera pas aux conditions d’éclairage. L’arrêt de ce service peut également affecter d’autres fonctionnalités du système.','Stopped','Manual'),
(2294,2,'SessionEnv','Configuration des services Bureau à distance','Le service Configuration des services Bureau à distance (RDCS) est responsable de toutes les activités de maintenance de session et de configuration du Bureau à distance et des services Bureau à distance nécessitant un contexte SYSTEM. Il faut y inclure les dossiers temporaires par session, ainsi que les thèmes et certificats des services Bureau à distance.','Stopped','Manual'),
(2295,2,'SessionSvc','Session Detection',NULL,'Running','Auto'),
(2296,2,'SharedAccess','Partage de connexion Internet (ICS)','Assure la traduction d’adresses de réseau, l’adressage, les services de résolution de noms et/ou les services de prévention d’intrusion pour un réseau de petite entreprise ou un réseau domestique.','Stopped','Manual'),
(2297,2,'ShellHWDetection','Détection matériel noyau','Fournit des notifications à des événements matériel de lecture automatique.','Running','Auto'),
(2298,2,'shpamsvc','Shared PC Account Manager','Manages profiles and accounts on a SharedPC configured device','Stopped','Disabled'),
(2299,2,'smphost','SMP de l’Espace de stockages Microsoft','Service hôte du fournisseur de gestion de l’Espace de stockages Microsoft. Si ce service est arrêté ou désactivé,  l’Espace de stockages ne peut pas être géré.','Stopped','Manual'),
(2300,2,'SmsRouter','Service Routeur SMS Microsoft Windows.','Achemine les messages vers les clients appropriés sur la base de règles.','Running','Auto'),
(2301,2,'SNMPTrap','Interruption SNMP','Reçoit les messages d’interception générés par les agents SNMP (Simple Network Management Protocol) locaux ou distants et transmet les messages aux programmes de gestion SNMP s’exécutant sur cet ordinateur. Si ce service est arrêté, les programmes à base SNMP sur cet ordinateur ne recevront pas les messages d’interception SNMP. Si ce service est désactivé, tous les services qui en dépendent explicitement ne pourront pas démarrer.','Stopped','Manual'),
(2302,2,'Spooler','Spouleur d’impression','Ce service met en spoule les travaux d’impression et gère l’interaction avec l’imprimante.  Si vous arrêtez ce service, vous ne pourrez plus imprimer ni voir vos imprimantes.','Running','Auto'),
(2303,2,'sppsvc','Protection logicielle','Permet le téléchargement, l’installation et l’application de licences numériques pour Windows et des applications Windows. Si le service est désactivé, le système d’exploitation et les applications sous licence peuvent s’exécuter dans un mode de notification. Et il est instamment recommandé de ne pas désactiver le service de protection logicielle.','Stopped','Auto'),
(2304,2,'SSDPSRV','Découverte SSDP','Découvre les périphériques et services en réseau qui utilisent le protocole de découverte SSDP, tels que les périphériques UPnP. Annonce également les périphériques et services SSDP exécutés sur l’ordinateur local. Si ce service est arrêté, les périphériques SSDP ne seront pas découverts. S’il est désactivé, tous les services qui dépendent explicitement de lui ne démarreront pas.','Running','Manual'),
(2305,2,'ssh-agent','OpenSSH Authentication Agent','Agent to hold private keys used for public key authentication.','Stopped','Disabled'),
(2306,2,'SstpSvc','Service SSTP (Secure Socket Tunneling Protocol)','Prend en charge la connexion par le protocole SSTP (Secure Socket Tunneling Protocol) à des ordinateurs distants via un réseau VPN. Si ce service est désactivé, les utilisateurs ne peuvent pas utiliser le protocole SSTP pour accéder à des serveurs distants.','Running','Manual'),
(2307,2,'StateRepository','Service State Repository (StateRepository)','Fournit la prise en charge d\'infrastructure nécessaire au modèle d\'application.','Running','Auto'),
(2308,2,'StiSvc','Acquisition d’image Windows (WIA)','Fournit des services d’acquisition d’images pour les scanneurs et les appareils photo.','Stopped','Manual'),
(2309,2,'StorSvc','Service de stockage','Fournit des services d\'activation pour les paramètres de stockage et l\'extension de stockage externe','Running','Auto'),
(2310,2,'SUService','System Update','Lenovo System Update','Stopped','Manual'),
(2311,2,'svsvc','Vérificateur de points','Vérifie les endommagements potentiels du système de fichiers.','Stopped','Manual'),
(2312,2,'swprv','Fournisseur de cliché instantané de logiciel Microsoft','Gère les copies logicielles de clichés instantanés de volumes créés par le service de cliché instantané de volumes. Si ce service est arrêté, les copies logicielles de clichés instantanés ne peuvent pas être gérées. Si le service est désactivé, les services qui en dépendent ne pourront pas démarrer.','Stopped','Manual'),
(2313,2,'SysMain','SysMain','Gère et améliore les performances du système dans le temps.','Running','Auto'),
(2314,2,'SystemEventsBroker','Service Broker des événements système','Coordonne l’exécution de travail en arrière-plan pour l’application WinRT. Si ce service est arrêté ou désactivé, le travail en arrière-plan risque de ne pas être déclenché.','Running','Auto'),
(2315,2,'TapiSrv','Téléphonie','Prend en charge l’interface TAPI (Telephony API) pour les programmes qui contrôlent les périphériques de téléphonie sur l’ordinateur local et, via le réseau local (LAN), sur les serveurs qui exécutent également le service.','Stopped','Manual'),
(2316,2,'TermService','Services Bureau à distance','Autorise les utilisateurs à se connecter de manière interactive à un ordinateur distant. Le Bureau à distance et le serveur hôte de session Bureau à distance dépendent de ce service. Pour empêcher l’utilisation à distance de cet ordinateur, désactivez les cases à cocher situées sous l’onglet Utilisation à distance des Propriétés système via l’élément Système du Panneau de configuration.','Stopped','Manual'),
(2317,2,'TextInputManagementService','Service de gestion des entrées de texte','Activer l’entrée de texte, les sentiments et émotions, le clavier tactile, l’écriture manuscrite et les éditeurs de méthode d’entrées instantanées.','Running','Auto'),
(2318,2,'Themes','Thèmes','Fournit un système de gestion de thème de l’expérience utilisateur.','Running','Auto'),
(2319,2,'TieringEngineService','Gestion des niveaux de stockage','Optimise le placement des données dans les niveaux de stockage de tous les espaces de stockage à plusieurs niveaux sur le système.','Stopped','Manual'),
(2320,2,'TimeBrokerSvc','Service Broker pour les événements horaires','Coordonne l’exécution de travail en arrière-plan pour l’application WinRT. Si ce service est arrêté ou désactivé, le travail en arrière-plan risque de ne pas être déclenché.','Running','Manual'),
(2321,2,'TokenBroker','Gestionnaire de comptes web','Ce service est utilisé par le Gestionnaire de comptes web pour fournir une authentification unique aux applications et aux services.','Running','Manual'),
(2322,2,'TPHKLOAD','Lenovo Hotkey Client Loader',NULL,'Running','Auto'),
(2323,2,'TrkWks','Client de suivi de lien distribué','Conserve les liens entre des fichiers NTFS au sein d’un ordinateur ou d’un ensemble d’ordinateurs en réseau.','Running','Auto'),
(2324,2,'TroubleshootingSvc','Service de résolution des problèmes recommandé','Permet l\'atténuation automatique pour des problèmes connus en appliquant la résolution des problèmes recommandée. S\'il est arrêté, votre appareil n\'obtiendra pas la résolution des problèmes recommandée pour les problèmes de votre appareil.','Stopped','Manual'),
(2325,2,'TrustedInstaller','Programme d’installation pour les modules Windows','Permet l’installation, la modification et la suppression de composants facultatifs et de mises à jour Windows. Si ce service est désactivé, l’installation ou la désinstallation de mises à jour Windows peut échouer pour cet ordinateur.','Running','Auto'),
(2326,2,'tzautoupdate','Programme de mise à jour automatique du fuseau horaire','Définit automatiquement le fuseau horaire système.','Stopped','Disabled'),
(2327,2,'UevAgentService','Service User Experience Virtualization','Assure la prise en charge de l’itinérance des paramètres d’application et de système d’exploitation','Stopped','Disabled'),
(2328,2,'UmRdpService','Redirecteur de port du mode utilisateur des services Bureau à distance','Permet la redirection des imprimantes/unités/ports pour les connexions RDP','Stopped','Manual'),
(2329,2,'upnphost','Hôte de périphérique UPnP','Autorise l’hébergement des périphériques UPnP sur cet ordinateur. Si ce service est arrêté, tous les périphériques UPnP hébergés cesseront de fonctionner et aucun autre périphérique hébergé ne pourra être ajouté. Si ce service est désactivé, tous les services qui dépendent explicitement de lui ne démarreront pas.','Stopped','Manual'),
(2330,2,'UserManager','Gestionnaire des utilisateurs','Le Gestionnaire des utilisateurs fournit les composants d\'exécution requis pour une interaction multi-utilisateur.  Si ce service est arrêté, certaines applications risquent de ne pas fonctionner correctement.','Running','Auto'),
(2331,2,'UsoSvc','Service Orchestrator pour les mises à jour','Gère les mises à jour Windows. Si cette fonctionnalité est arrêtée, vos appareils ne pourront pas télécharger ni installer les dernières mises à jour.','Running','Auto'),
(2332,2,'VaultSvc','Gestionnaire d’informations d’identification','Offre un service de stockage et de récupération sécurisé des informations d’identification pour les utilisateurs, les applications et les packages de services de sécurité.','Running','Manual'),
(2333,2,'vds','Disque virtuel','Fournit des services de gestion des disques, des volumes, des systèmes de fichiers et des groupes de stockage.','Stopped','Manual'),
(2334,2,'vmicguestinterface','Interface de services d’invité Hyper-V','Fournit une interface à l’hôte Hyper-V afin qu’il puisse interagir avec des services spécifiques s’exécutant sur l’ordinateur virtuel.','Stopped','Manual'),
(2335,2,'vmicheartbeat','Service Pulsation Microsoft Hyper-V','Surveille l‘état de cet ordinateur virtuel en émettant une pulsation à intervalles réguliers. Ce service vous permet d’identifier les ordinateurs virtuels en cours d’exécution qui ne répondent plus.','Stopped','Manual'),
(2336,2,'vmickvpexchange','Service Échange de données Microsoft Hyper-V','Propose un mécanisme d’échange de données entre l’ordinateur virtuel et le système d’exploitation exécuté sur l’ordinateur physique.','Stopped','Manual'),
(2337,2,'vmicrdv','Service de virtualisation Bureau à distance Hyper-V','Fournit une plateforme pour la communication entre l’ordinateur virtuel et le système d’exploitation exécuté sur l’ordinateur physique.','Stopped','Manual'),
(2338,2,'vmicshutdown','Service Arrêt de l’invité Microsoft Hyper-V','Propose un mécanisme permettant d’arrêter le système d’exploitation de cet ordinateur virtuel à partir des interfaces de gestion de l’ordinateur physique.','Stopped','Manual'),
(2339,2,'vmictimesync','Service Synchronisation date/heure Microsoft Hyper-V','Synchronise l’heure système de cet ordinateur virtuel avec l’heure système de l’ordinateur physique.','Stopped','Manual'),
(2340,2,'vmicvmsession','Service Hyper-V PowerShell Direct','Fournit un mécanisme de gestion des ordinateurs virtuels avec PowerShell via une session d\'ordinateur virtuel sans réseau virtuel.','Stopped','Manual'),
(2341,2,'vmicvss','Requête du service VSS Hyper-V','Coordonne les communications nécessaires à l’utilisation du service VSS afin de sauvegarder les applications et les données de cet ordinateur virtuel à partir du système d’exploitation de l’ordinateur physique.','Stopped','Manual'),
(2342,2,'VSS','Cliché instantané des volumes','Gère et implémente les clichés instantanés de volumes pour les sauvegardes et autres utilisations. Si ce service est arrêté, les clichés instantanés ne seront pas disponibles pour la sauvegarde et la sauvegarde échouera. Si ce service est désactivé, les services en dépendant explicitement ne démarreront pas.','Stopped','Manual'),
(2343,2,'W32Time','Temps Windows','Conserve la synchronisation de la date et de l’heure sur tous les clients et serveurs sur le réseau. Si ce service est arrêté, la synchronisation de la date et de l’heure sera indisponible. Si ce service est désactivé, tout service en dépendant explicitement ne démarrera pas.','Stopped','Manual'),
(2344,2,'WaaSMedicSvc','WaaSMedicSvc',NULL,'Stopped','Manual'),
(2345,2,'WalletService','WalletService','Objets d\'hôtes utilisés par les clients du portefeuille','Stopped','Manual'),
(2346,2,'WarpJITSvc','Warp JIT Service','Enables JIT compilation support in d3d10warp.dll for processes in which code generation is disabled.','Stopped','Manual'),
(2347,2,'wbengine','Service de moteur de sauvegarde en mode bloc','Le service WBENGINE est utilisé par la sauvegarde Windows pour effectuer les opérations de sauvegarde et de récupération. Si ce service est arrêté par un utilisateur, l’opération de sauvegarde ou de récupération en cours risque d’échouer. La désactivation de ce service peut désactiver les opérations de sauvegarde et de récupération effectuées à l’aide de la sauvegarde Windows sur cet ordinateur.','Stopped','Manual'),
(2348,2,'WbioSrvc','Service de biométrie Windows','Le service de biométrie Windows permet aux applications clientes de capturer, comparer, manipuler et stocker des données biométriques sans avoir directement accès au matériel ou aux échantillons. Le service est hébergé dans un processus SVCHOST privilégié.','Stopped','Auto'),
(2349,2,'Wcmsvc','Gestionnaire des connexions Windows','Prends des décisions automatiques de connexion et de déconnexion en fonction des options de connectivité réseau actuellement disponibles pour le PC et permet la gestion de la connectivité réseau sur la base des paramètres de stratégie de groupe.','Running','Auto'),
(2350,2,'wcncsvc','Windows Connect Now - Registre de configuration','WCNCSVC héberge la configuration de connexion immédiate Windows, qui est l\'implémentation Microsoft du protocole WPS (Wireless Protected Setup). On l\'utilise pour configurer des paramètres de réseau local sans fil pour un point d\'accès ou un périphérique sans fil. Le service est démarré par programme en cas de besoin.','Stopped','Manual'),
(2351,2,'WdiServiceHost','Service hôte WDIServiceHost','Le service Hôte de service de diagnostics est utilisé par le Service de stratégie de diagnostics pour héberger les diagnostics qui doivent être exécutés dans un contexte de service local. Si ce service est arrêté, tous les diagnostics qui en dépendent ne fonctionneront plus.','Stopped','Manual'),
(2352,2,'WdiSystemHost','Hôte système de diagnostics','Le service Hôte système de diagnostics est utilisé par le Service de stratégie de diagnostics pour héberger les diagnostics qui doivent être exécutés dans un contexte de système local. Si ce service est arrêté, tous les diagnostics qui en dépendent ne fonctionneront plus.','Running','Manual'),
(2353,2,'WdNisSvc','Service d’inspection réseau de l’antivirus Microsoft Defender','Empêche les tentatives d’intrusion ciblant les vulnérabilités connues et nouvellement découvertes des protocoles réseau','Stopped','Manual'),
(2354,2,'WebClient','WebClient','Permet à un programme fonctionnant sous Windows de créer, modifier et accéder à des fichiers Internet. Si ce service est arrêté, ces fonctions ne sont pas disponibles. Si ce service est désactivé, tous les services qui en dépendent explicitement ne peuvent plus démarrer.','Stopped','Manual'),
(2355,2,'webthreatdefsvc','Service Web Threat Defense','Le service de point de terminaison Web Threat Defense vous aide à protéger votre ordinateur en identifiant les entités non autorisées tentant d’accéder aux informations d’identification de l’utilisateur','Stopped','Manual'),
(2356,2,'Wecsvc','Collecteur d’événements de Windows','Ce service gère des abonnements persistants à des événements de sources distantes prenant en charge le protocole Gestion de services Web. Cela inclut les journaux d’événements de Windows Vista, les sources d’événements matériels et IPMI. Le service stocke les événements transférés dans un journal d’événements local. Si ce service est arrêté ou désactivé, des abonnements aux événements ne peuvent pas être créés et les événements transférés ne peuvent pas être acceptés.','Stopped','Manual'),
(2357,2,'WEPHOSTSVC','Service hôte du fournisseur de chiffrement Windows','Le service hôte du fournisseur de chiffrement Windows négocie les fonctionnalités liées au chiffrement avec les fournisseurs de chiffrement tiers pour les processus qui ont besoin d’évaluer et d’appliquer des stratégies EAS. L’arrêt de cette activité compromettra les vérifications de conformité EAS qui ont été établies par les comptes de messagerie connectés.','Stopped','Manual'),
(2358,2,'wercplsupport','Prise en charge du Panneau de configuration Rapports de problèmes','Ce service prend en charge l’affichage, l’envoi et la suppression de rapports de problèmes au niveau du système pour l’application Rapports de problèmes du Panneau de configuration.','Stopped','Manual'),
(2359,2,'WerSvc','Service de rapport d’erreurs Windows','Autorise le signalement des erreurs lorsque des programmes cessent de fonctionner ou de répondre, ainsi que la fourniture de solutions existantes. Autorise également la génération de journaux pour les services de diagnostic et de réparation. Si ce service est arrêté, le signalement des erreurs risque de ne pas fonctionner correctement ; par ailleurs, les résultats des services de diagnostic et de réparation risquent de ne pas s’afficher.','Stopped','Manual'),
(2360,2,'WFDSConMgrSvc','Service Wi-Fi Direct Service de gestionnaire de connexions','Gère les connexions aux services sans fil, y compris l’affichage sans fil et la station d’accueil.','Stopped','Manual'),
(2361,2,'whesvc','Intégrité de Windows et expériences optimisées','Surveille l’appareil pour une meilleure expérience utilisateur','Running','Auto'),
(2362,2,'WiaRpc','Événements d’acquisition d’images fixes','Lance les applications associées aux événements d’acquisition d’images fixes.','Stopped','Manual'),
(2363,2,'WinDefend','Service antivirus Microsoft Defender','Protège les utilisateurs contre les logiciels malveillants et les autres logiciels potentiellement indésirables','Running','Auto'),
(2364,2,'WinHttpAutoProxySvc','Service de découverte automatique de Proxy Web pour les services HTTP Windows','WinHTTP implémente la pile HTTP du client et fournit aux développeurs une API Win32 et un composant d’automatisation COM pour l’envoi des demandes HTTP et la réception des réponses. En outre, WinHTTP prend en charge la découverte automatique d’une configuration de proxy via son implémentation du protocole WPAD (Web Proxy Auto-Discovery).','Running','Manual'),
(2365,2,'Winmgmt','Infrastructure de gestion Windows','Fournit une interface commune et un modèle objet pour accéder aux informations de gestion du système d’exploitation, des périphériques, des applications et des services. Si ce service est arrêté, la plupart des logiciels sur base Windows ne fonctionneront pas correctement. Si ce service est désactivé, tout service qui en dépend explicitement ne démarrera pas.','Running','Auto'),
(2366,2,'WinRM','Gestion à distance de Windows (Gestion WSM)','Le service Gestion à distance de Windows implémente le protocole Gestion des services Web pour la gestion à distance. La Gestion des services Web est un protocole standard utilisé pour la gestion à distance de logiciels et de matériels. Le service Gestion à distance de Windows traite les demandes Gestion des services Web. Il doit être configuré à l’aide de l’outil winrm.cmd ou via la stratégie de groupe. Ce service donne accès aux données WMI et permet le recueil d’événements. Le recueil d’événements et l’abonnement exigent que ce service s\'exécute. Les messages du service Gestion à distance de Windows utilisent HTTP et HTTPS. Le service Gestion à distance de Windows ne dépend pas d’IIS mais partage un port avec IIS sur la même machine. Le service Gestion à distance de Windows réserve le préfixe d’URL /wsman. Pour éviter les conflits avec IIS, vérifiez que les sites Web hébergés sur IIS n’utilisent pas le préfixe d’URL /wsman.','Stopped','Manual'),
(2367,2,'wisvc','Service Windows Insider','Offre la prise en charge de l\'infrastructure pour le programme Windows Insider. Ce service doit rester actif pour que le programme Windows Insider fonctionne.','Stopped','Manual'),
(2368,2,'WlanSvc','Service de configuration automatique WLAN','Le service WLANSVC fournit la logique nécessaire pour configurer, découvrir, se connecter et se déconnecter d’un réseau local sans fil (WLAN) tel que défini par les normes IEEE 802.11. Il contient également la logique permettant de convertir votre ordinateur en un point d’accès logiciel de sorte que d’autres périphériques ou ordinateurs puissent se connecter à votre ordinateur sans fil à l’aide d’une carte WLAN prenant en charge cette fonctionnalité. L’arrêt ou la désactivation du service WLANSVC rendront toutes les cartes WLAN sur votre ordinateur inaccessibles à partir de l’interface utilisateur de mise en réseau Windows. Il est vivement recommandé d’exécuter le service WLANSVC si votre ordinateur possède une carte WLAN.','Running','Auto'),
(2369,2,'wlidsvc','Assistant Connexion avec un compte Microsoft','Autorise la connexion des utilisateurs par le biais des services d’identité de compte Microsoft. Si ce service est arrêté, les utilisateurs ne pourront pas ouvrir une session sur l’ordinateur avec leur compte Microsoft.','Stopped','Manual'),
(2370,2,'wlpasvc','Service de l’Assistant de profil local','Ce service fournit la gestion du profil pour les modules d’identité d’abonné','Stopped','Manual'),
(2371,2,'WManSvc','Service de gestion de Windows','Effectue la gestion, notamment les activités d\'approvisionnement et d\'inscription','Stopped','Manual'),
(2372,2,'wmiApSrv','Carte de performance WMI','Fournit des informations concernant la bibliothèque de performance à partir des fournisseurs HiPerf WMI (Windows Management Instrumentation) à des clients sur le réseau. Ce service s’exécute uniquement quand l’assistant de performance des données est activé.','Running','Manual'),
(2373,2,'WMIRegistrationService','Intel(R) Management Engine WMI Provider Registration','Intel(R) Management Engine WMI Provider Registration Service','Running','Auto'),
(2374,2,'WMPNetworkSvc','Service de partage réseau du Lecteur multimédia Windows','Partage les bibliothèques du Lecteur multimédia Windows avec des lecteurs réseau et des appareils multimédias qui utilisent le Plug-and-Play universel','Stopped','Manual'),
(2375,2,'workfolderssvc','Dossiers de travail','Ce service synchronise des fichiers avec le serveur Dossiers de travail, vous permettant ainsi d’utiliser ces fichiers sur tous les PC et appareils sur lesquels vous avez configuré la fonctionnalité Dossiers de travail.','Stopped','Manual'),
(2376,2,'WpcMonSvc','Contrôle parental','Applique le contrôle parental aux comptes enfant dans Windows. Si ce service est arrêté ou désactivé, le contrôle parental peut ne pas être appliqué.','Stopped','Manual'),
(2377,2,'WPDBusEnum','Service Énumérateur d’appareil mobile','Met en place une stratégie de groupe pour les dispositifs de stockage de masse amovibles. Permet à des applications telles que le Lecteur multimédia Windows et l’Assistant Importation d’images de transférer et de synchroniser du contenu à l’aide de dispositifs de stockage de masse amovibles.','Stopped','Manual'),
(2378,2,'WpnService','Service du système de notifications Push Windows','Ce service s’exécute dans la session 0 et héberge la plateforme de notification et le fournisseur de connexion qui gère la connexion entre l’appareil et le serveur WNS.','Running','Auto'),
(2379,2,'WSAIFabricSvc','WSAIFabricSvc','Assure la prise en charge de la communication avec AIFabric dans le contexte de service local sur COM.','Running','Auto'),
(2380,2,'wscsvc','Centre de sécurité','Le service WSCSVC (Centre de sécurité Windows) surveille et affiche les paramètres d\'intégrité de la sécurité de l\'ordinateur. Parmi les paramètres d\'intégrité figurent ceux du pare-feu (activé/désactivé), de l\'antivirus (activé/désactivé/périmé), du logiciel anti-espion (activé/désactivé/périmé), de Windows Update (téléchargement et installation automatiques/manuels des mises à jour), du Contrôle de compte d\'utilisateur (activé/désactivé) et des paramètres Internet (recommandés/non recommandés). Le service fournit des API COM à l\'intention des éditeurs de logiciels indépendants pour qu\'ils s\'inscrivent et enregistrent l\'état de leurs produits auprès du service Centre de sécurité. L\'interface utilisateur de la fonctionnalité Sécurité et maintenance utilise le service pour fournir des alertes dans la zone de notification et une vue graphique des états d\'intégrité de la sécurité dans le panneau de configuration de Sécurité et maintenance. La Protection d\'accès réseau (NAP) utilise le service pour signaler les états d\'intégrité de la sécurité des clients au serveur NPS (Network Policy Server) et prendre les décisions de mise en quarantaine réseau. Le service contient également une API publique permettant aux consommateurs externes de récupérer par programme l\'état d\'intégrité consolidé de la sécurité du système.','Running','Auto'),
(2381,2,'WSearch','Windows Search','Fournit des fonctionnalités d’indexation de contenu, de mise en cache des propriétés, de résultats de recherche pour les fichiers, les messages électroniques et autres contenus.','Running','Auto'),
(2382,2,'wuauserv','Windows Update','Active la détection, le téléchargement et l’installation des mises à jour de Windows et d’autres programmes. Si ce service est désactivé, les utilisateurs de cet ordinateur ne pourront pas utiliser Windows Update ou sa fonctionnalité de mise à jour automatique, et les programmes ne pourront pas utiliser l’API de l’Agent de mise à jour automatique Windows Update (WUA).','Running','Manual'),
(2383,2,'wuqisvc','Informations sur l’utilisation et la qualité de Microsoft','Un service Microsoft produisant des faits récapitulatifs et des insights relatifs à l’utilisation et à la qualité de l’expérience. Les faits sont utilisés pour automatiser la réparation spontanée sur l’appareil et d’autres flux de travail facultatifs, tels que des offres personnalisées.','Running','Manual'),
(2384,2,'WwanSvc','Service de configuration automatique WWAN','Ce service gère les connexions et adaptateurs de module intégré/carte de données à haut débit mobile (GSM & CDMA) en configurant automatiquement les réseaux. Il est vivement recommandé de laisser ce service s’exécuter afin d’améliorer l’expérience des utilisateurs de haut débit mobile.','Running','Auto'),
(2385,2,'XblAuthManager','Gestionnaire d\'authentification Xbox Live','Fournit des services d\'authentification et d\'autorisation pour interagir avec Xbox Live. Si ce service est arrêté, certaines applications peuvent ne pas fonctionner correctement.','Stopped','Manual'),
(2386,2,'XblGameSave','Jeu sauvegardé sur Xbox Live','Ce service synchronise les données enregistrées pour les jeux dont la sauvegarde sur Xbox Live est activée. Si ce service est arrêté, les données enregistrées des jeux ne seront téléchargées ni vers, ni depuis Xbox Live.','Stopped','Manual'),
(2387,2,'XboxGipSvc','Xbox Accessory Management Service','This service manages connected Xbox Accessories.','Stopped','Manual'),
(2388,2,'XboxNetApiSvc','Service de mise en réseau Xbox Live','Ce service prend en charge l\'interface de programmation d\'application Windows.Networking.XboxLive.','Stopped','Manual'),
(2389,2,'ZoomCptService','Zoom Sharing Service','Enable Zoom meeting participants to control your desktop. If this service is stopped or disabled, remote users won\'t control any applications running at a High Integrity level.','Running','Auto'),
(2390,2,'AarSvc_b0675','Agent Activation Runtime_b0675','Runtime for activating conversational agent applications','Stopped','Manual'),
(2391,2,'BcastDVRUserService_b0675','Service utilisateur de diffusion et GameDVR_b0675','Ce service utilisateur est utilisé pour les enregistrements de jeu et les diffusions en direct','Stopped','Manual'),
(2392,2,'BluetoothUserService_b0675','Service de support des utilisateurs du Bluetooth_b0675','Le service des utilisateurs du Bluetooth prend en charge le bon fonctionnement de fonctionnalités Bluetooth pertinentes pour chaque session utilisateur.','Running','Manual'),
(2393,2,'CaptureService_b0675','CaptureService_b0675','Active la fonctionnalité de capture d\'écran facultative pour les applications qui appellent l\'API Windows.Graphics.Capture.','Stopped','Manual'),
(2394,2,'cbdhsvc_b0675','Service utilisateur du Presse-papiers_b0675','Ce service utilisateur est utilisé pour les scénarios du Presse-papiers','Running','Auto'),
(2395,2,'CDPUserSvc_b0675','Service pour utilisateur de plateforme d’appareils connectés_b0675','Ce service utilisateur entre dans le cadre de scénarios de plateforme d’appareils connectés','Running','Auto'),
(2396,2,'CloudBackupRestoreSvc_b0675','Service de restauration et de sauvegarde dans le cloud_b0675','Surveille le système pour détecter des modifications apportées aux états de l’application et des paramètres, et effectue des opérations de sauvegarde et de restauration dans le cloud si nécessaire.','Stopped','Manual'),
(2397,2,'ConsentUxUserSvc_b0675','Service utilisateur ConsentUX_b0675','Permet au système de demander l’autorisation de l’utilisateur pour autoriser les applications à accéder à des ressources sensibles et à des informations telles que l’emplacement de l’appareil','Stopped','Manual'),
(2398,2,'CredentialEnrollmentManagerUserSvc_b0675','CredentialEnrollmentManagerUserSvc_b0675','Gestionnaire d’inscription des informations d’identification','Stopped','Manual'),
(2399,2,'DeviceAssociationBrokerSvc_b0675','DeviceAssociationBroker_b0675','Enables apps to pair devices','Stopped','Manual'),
(2400,2,'DevicePickerUserSvc_b0675','DevicePicker_b0675','Ce service utilisateur permet de gérer l\'IU Miracast, DLNA et DIAL','Stopped','Manual'),
(2401,2,'DevicesFlowUserSvc_b0675','Flux d’appareils_b0675','Permet à ConnectUX et aux Paramètres du PC de se connecter et d\'effectuer le couplage avec affichages Wi-Fi et les appareils Bluetooth.','Running','Manual'),
(2402,2,'MessagingService_b0675','MessagingService_b0675','Service prenant en charge les envois de SMS et les fonctionnalités associées.','Stopped','Auto'),
(2403,2,'NPSMSvc_b0675','Lecture en cours du service du Responsable de la session_b0675','Ce service héberge le Responsable de la session de lecture en cours utilisé pour les scénarios multimédias','Running','Manual'),
(2404,2,'OneSyncSvc_b0675','Hôte de synchronisation_b0675','Ce service synchronise la messagerie, les contacts, le calendrier et diverses autres données utilisateur. La messagerie et d\'autres applications dépendantes de cette fonctionnalité ne fonctionnent pas correctement lorsque ce service n\'est pas exécuté.','Running','Auto'),
(2405,2,'P9RdrService_b0675','P9RdrService_b0675','Active le déclencheur en démarrant les serveurs de fichiers plan9.','Stopped','Manual'),
(2406,2,'PenService_b0675','PenService_b0675','Service de gestion du stylet','Stopped','Manual'),
(2407,2,'PimIndexMaintenanceSvc_b0675','Données de contacts_b0675','Indexe les données de contacts pour une recherche des contacts plus rapide. Si vous arrêtez ou désactivez ce service, des contacts risquent de manquer dans vos résultats de recherche.','Running','Manual'),
(2408,2,'PrintWorkflowUserSvc_b0675','PrintWorkflow_b0675','Assure la prise en charge des applications Flux de travail d’impression. Si vous désactivez ce service, vous risquez de ne pas pouvoir imprimer correctement.','Stopped','Manual'),
(2409,2,'UdkUserSvc_b0675','Service utilisateur du kit de développement sans station d’accueil_b0675','Service de composants d\'environnement','Running','Manual'),
(2410,2,'UnistoreSvc_b0675','Stockage des données utilisateur_b0675','Gère le stockage des données utilisateur structurées, notamment les coordonnées, les calendriers, les messages et d’autres éléments de contenu. Si vous arrêtez ou désactivez ce service, les applications qui utilisent ces données risquent de ne pas fonctionner correctement.','Running','Manual'),
(2411,2,'UserDataSvc_b0675','Accès aux données utilisateur_b0675','Fournit l’accès des applications aux données utilisateur structurées, notamment aux coordonnées, calendriers, messages et autres éléments de contenu. Si vous arrêtez ou désactivez ce service, les applications qui utilisent ces données risquent de ne pas fonctionner correctement.','Running','Manual'),
(2412,2,'webthreatdefusersvc_b0675','Service d’utilisateur Web Threat Defense_b0675','Le service d’utilisateur Web Threat Defense vous aide à protéger l’ordinateur en avertissant l’utilisateur lorsque des entités non autorisées tentent d’accéder à leurs informations d’identification','Running','Auto'),
(2413,2,'WpnUserService_b0675','Service utilisateur de notifications Push Windows_b0675','Ce service héberge la plateforme de notification Windows qui fournit la prise en charge des notifications locales et Push. Les notifications prises en charge sont tile, toast et raw.','Running','Auto'),
(2414,2,'IntelGraphicsSoftwareService','Intel® Graphics Software','Intel® Graphics Software','Running','Auto'),
(2415,2,'ekrn','ESET Service','ESET Service','Running','Auto'),
(2416,2,'efwd','ESET Forwarder','ESET Communication Forwarding Service','Running','Auto'),
(2417,2,'ekrnEpfw','ESET Firewall Helper',NULL,'Running','Manual'),
